    dueAt.setUTCHours(16, 0, 0, 0);

    await client.query("DELETE FROM workflow_state");
    await client.query("DELETE FROM owner_tasks");
    await client.query("DELETE FROM customer_messages");
    await client.query("DELETE FROM audit_events");

    await client.query(
      "INSERT INTO workflow_state (request_id, account_id, title, status, next_step, risk_summary) VALUES ($1, $2, $3, $4, $5, $6)",
      [requestId, accountId, "Strategic Account Rescue", status, nextStep, riskSummary]
    );

    for (const owner of owners) {
      await client.query(
        "INSERT INTO owner_tasks (request_id, account_id, owner_group, title, due_at, status) VALUES ($1, $2, $3, $4, $5, $6)",
        [requestId, accountId, owner, `${owner} recovery action`, dueAt.toISOString(), "open"]
      );
    }

    const customerMsg = qualifies
      ? `Your account has been identified for priority attention due to active risk indicators. Our team has initiated a recovery workflow and assigned dedicated owners to address the concerns. We are committed to resolving these matters promptly and will be in touch to coordinate next steps and ensure your continued success.`
      : `Your account is under standard monitoring and no escalation is required at this time. Please contact us if you have any questions.`;

    await client.query(
      "INSERT INTO customer_messages (request_id, account_id, body) VALUES ($1, $2, $3)",
      [requestId, accountId, customerMsg]
    );

    const event = qualifies
      ? `Escalation workflow initiated. ${signals.length} risk signals detected. Recovery owners assigned: ${owners.join(", ")}.`
      : `Account monitoring check completed. No escalation required.`;

    await client.query(
      "INSERT INTO audit_events (request_id, account_id, event, occurred_at, customer_visible) VALUES ($1, $2, $3, $4, $5)",
      [requestId, accountId, event, nowDate.toISOString(), true]
    );
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
}
